//increase damage dealt 15%
<Custom Confirm Effect>
var isDamage = this.isPhysical() && this.isHpEffect() && value > 0;
if (isDamage){value = Math.ceil(value * 1.15);}
</Custom Confirm Effect>

//increase damage received 15%
<Custom React Effect>
var isDamage = this.isPhysical() && this.isHpEffect() && value > 0;
if (isDamage){value = Math.floor(value * 1.15);}
</Custom React Effect>

// NEEDS A STATE ICON
<Category: Bypass Death Removal>
<Custom Confirm Effect>
var isDamage = this.isPhysical() && this.isHpEffect() && value > 0;
if (isDamage && value > 0 && target.hpRate() < 0.5) {
  value = Math.ceil(value * 1.2);
}
</Custom Confirm Effect>

// Similar to SAD
<Category: Bypass Death Removal>
<Custom React Effect>
if (value > 0 && this.isHpEffect()) {
  var mpDmg = Math.floor(value * 0.2);
  mpDmg = Math.min(mpDmg, target.mp);
  target.gainMp(-mpDmg);
  value -= mpDmg;
}
</Custom React Effect>
